import java.util.ArrayList;

abstract class Shape {
    int posx;
    int posy;
    int col;
    float vx = random(-20, 20);
    float vy = random(-20, 20);
    int size = int(random(30));

    abstract void gen();
    public void update() {
        posx += vx;
        posy += vy;

        //bring vx and vy closer to 0
        vx = vx / 1.1;
        vy = vy / 1.1;

        if (vx <= 1) {
            vx = 1;
        }
        if (vy <= 1) {
            vy = 1;
        }
    }
    abstract void updraw();
}

class Square extends Shape {
    public void gen() {
        posx = mouseX;
        posy = mouseY;
        size = 20;
        col = #17181A;
        square(posx, posy, size);
    }
    public void updraw() {
           fill(col);
        square(posx, posy, size);
    }
}
class Circle extends Shape {
    public void gen() {
        posx = mouseX;
        posy = mouseY;
        size = 20;
        col = #FFFFFF;
        circle(posx, posy, size);
    }
    public void updraw() {
        fill(col);
        circle(posx, posy, size);
    }
}

class Triangle extends Shape {
    public void gen() {
        posx = mouseX;
        posy = mouseY;
        size = 20;
        col = #FFFFFF;
        triangle(posx+size, posy-size, posx-size, posy+size, posx+size, posy+size);
    }
    public void updraw() {
        fill(col);
        triangle(posx+size, posy-size, posx-size, posy+size, posx+size, posy+size);
    }
}

ArrayList<Shape> shapes = new ArrayList<Shape>();

void setup(){
    size(500,500);
}

void draw(){
    background(#FFFFFF);
    for (int i = 0; i < shapes.size(); i++){
        shapes.get(i).update();
        shapes.get(i).updraw();
    }
}

void mouseClicked() {
    int seed = int(random(3));
    Shape x;
    if (seed == 0) {
        x = new Triangle();
    } else if (seed == 1) {
        x = new Circle();
    } else {
        x = new Square();
    }
    x.gen();
    shapes.add(x);
}

